export type OptionsType<
  T extends unknown = unknown,
  TApiParams = never,
> = CreateStateOptionsType & {
  log?: boolean;
  componentId?: string;
  syncOptions?: SyncOptionsType<TApiParams>;

  serverState?: {
    id?: string | number;
    data?: T;
    status?: 'pending' | 'error' | 'success' | 'loading';
    timestamp?: number;
    merge?:
      | boolean
      | {
          strategy: 'append' | 'prepend' | 'diff';
          key?: string;
        };
  };

  sync?: {
    action: (state: T) => Promise<{
      success: boolean;
      data?: any;
      error?: any;
      errors?: Array<{
        path: (string | number)[];
        message: string;
      }>;
    }>;
    onSuccess?: (data: any) => void;
    onError?: (error: any) => void;
  };
  middleware?: ({ update }: { update: UpdateTypeDetail }) => void;

  localStorage?: {
    key: string | ((state: T) => string);
    onChange?: (state: T) => void;
  };

  reactiveDeps?: (state: T) => any[] | true;
  reactiveType?: ReactivityType;
  syncUpdate?: Partial<UpdateTypeDetail>;

  defaultState?: T;

  dependencies?: any[];
};
type ScopedPluginApi<THookReturn, TFieldMetaData> = {
  hookData: THookReturn;
  getFieldMetaData: () => TFieldMetaData | undefined;
  setFieldMetaData: (data: Partial<TFieldMetaData>) => void;
  // Add any other scoped functions or data a plugin might need here
};
export type FormsElementsType<
  TState,
  TPlugins extends readonly CogsPlugin<any, any, any, any, any>[] = [],
> = {
  // These optional, built-in wrappers are unchanged.
  validation?: (options: {
    children: React.ReactNode;
    status: ValidationStatus;
    severity: ValidationSeverity;
    hasErrors: boolean;
    hasWarnings: boolean;
    allErrors: ValidationError[];
    path: string[];
    message?: string;
    getData?: () => TState;
    plugins: {
      // It maps over the plugins...
      [P in TPlugins[number] as P['name']]: P extends CogsPlugin<
        any,
        any,
        infer THookReturn,
        any,
        infer TFieldMetaData
      >
        ? // ...and provides the scoped API for each one.
          ScopedPluginApi<THookReturn, TFieldMetaData>
        : never;
    };
  }) => React.ReactNode;
  syncRender?: (options: {
    children: React.ReactNode;
    time: number;
    data?: TState;
    key?: string;
  }) => React.ReactNode;
};
